#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
BOT LENGKAP - HEWAN JOGET DANGDUT VIRAL
Upload 10 video/hari ke Facebook, ambil musik viral dari FB, gerakan sinkron.
Tidak perlu install apa pun manual. Semua otomatis.
"""

import subprocess
import sys
import os
import tempfile
import time
import random
import asyncio
import json
import base64
from datetime import datetime

# ================= AUTO INSTALL SEMUA DEPENDENSI =================
print("🔧 Memeriksa dan menginstall semua kebutuhan...")

required_packages = [
    "moviepy",
    "requests",
    "beautifulsoup4",
    "yt-dlp",
    "librosa",
    "soundfile",
    "pyppeteer",
    "imageio[ffmpeg]"
]

for package in required_packages:
    package_name = package.replace("[ffmpeg]", "")
    try:
        __import__(package_name.replace("-", "_"))
        print(f"✅ {package_name} sudah ada")
    except ImportError:
        print(f"📦 Menginstall {package}...")
        subprocess.check_call([sys.executable, "-m", "pip", "install", "-q", package])

# ================= IMPORT SETELAH INSTALL =================
import requests
from bs4 import BeautifulSoup
import yt_dlp
import librosa
import numpy as np
from PIL import Image
from io import BytesIO
from moviepy.editor import *
from pyppeteer import launch

# ================= KONFIGURASI =================
TARGET_VIDEO_PER_HARI = 10
JEDA_DETIK = int(24 * 3600 / TARGET_VIDEO_PER_HARI)  # 8640 detik = 2.4 jam
KEYWORD_SEARCH = "dangdut koplo viral reels"
SESSION_FILE = "fb_session.json"
LOG_FILE = "bot_log.txt"

# ================= GAMBAR HEWAN DALAM BASE64 (SUDAH TERMASUK) =================
# Tiga gambar: kucing, anjing, bebek
IMAGES_BASE64 = {
    "kucing": "",
    "anjing": "",
    "bebek": ""
}

def simpan_gambar_dari_base64():
    gambar_files = []
    for nama, b64 in IMAGES_BASE64.items():
        img_data = base64.b64decode(b64)
        img = Image.open(BytesIO(img_data))
        img = img.resize((1080, 1920))
        temp_file = tempfile.NamedTemporaryFile(delete=False, suffix=".jpg")
        img.save(temp_file.name)
        gambar_files.append(temp_file.name)
    return gambar_files

# ================= FUNGSI LOG =================
def tulis_log(pesan):
    waktu = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    with open(LOG_FILE, "a", encoding="utf-8") as f:
        f.write(f"[{waktu}] {pesan}\n")
    print(f"[{waktu}] {pesan}")

# ================= 1. SCRAPE URL REELS TRENDING =================
def scrape_trending_reels(keyword=KEYWORD_SEARCH, limit=5):
    tulis_log(f"Mencari reels dangdut viral: {keyword}")
    search_url = f"https://www.facebook.com/search/top?q={keyword.replace(' ', '+')}"
    headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'}
    try:
        resp = requests.get(search_url, headers=headers, timeout=30)
        soup = BeautifulSoup(resp.text, 'html.parser')
        reels_urls = []
        for a in soup.find_all('a', href=True):
            href = a['href']
            if '/reel/' in href or '/watch/?v=' in href:
                full = 'https://www.facebook.com' + href.split('?')[0] if not href.startswith('http') else href.split('?')[0]
                if full not in reels_urls and 'facebook.com' in full:
                    reels_urls.append(full)
                if len(reels_urls) >= limit:
                    break
        if reels_urls:
            tulis_log(f"Ditemukan {len(reels_urls)} URL reels")
            return reels_urls
    except Exception as e:
        tulis_log(f"Gagal scrape: {e}")
    fallback = ["https://www.facebook.com/reel/1523836417786597", "https://www.facebook.com/watch?v=1059815859753951"]
    tulis_log(f"Pakai fallback URL")
    return fallback

# ================= 2. DOWNLOAD AUDIO DARI REELS =================
def download_audio_from_reels(reel_url):
    tulis_log(f"Download audio dari: {reel_url}")
    out_template = tempfile.NamedTemporaryFile(delete=False, suffix=".mp3").name
    ydl_opts = {
        'format': 'bestaudio/best',
        'outtmpl': out_template.replace('.mp3', ''),
        'postprocessors': [{'key': 'FFmpegExtractAudio', 'preferredcodec': 'mp3', 'preferredquality': '192'}],
        'quiet': True,
        'no_warnings': True,
    }
    try:
        with yt_dlp.YoutubeDL(ydl_opts) as ydl:
            ydl.extract_info(reel_url, download=True)
        audio_path = out_template.replace('.mp3', '') + '.mp3'
        tulis_log(f"Audio selesai: {audio_path}")
        return audio_path
    except Exception as e:
        tulis_log(f"Gagal download audio: {e}")
        return None

# ================= 3. ANALISIS BEAT =================
def get_beat_times(audio_path):
    try:
        y, sr = librosa.load(audio_path, duration=60)
        tempo, beat_frames = librosa.beat.beat_track(y=y, sr=sr)
        beat_times = librosa.frames_to_time(beat_frames, sr=sr).tolist()
        duration = librosa.get_duration(y=y, sr=sr)
        tulis_log(f"Tempo: {tempo:.1f} BPM, Beat: {len(beat_times)}, Durasi: {duration:.1f}s")
        return {'beat_times': beat_times, 'tempo': tempo, 'duration': duration}
    except Exception as e:
        tulis_log(f"Gagal analisis beat: {e}")
        return None

# ================= 4. GENERATE VIDEO HEWAN JOGET SINKRON =================
def generate_sync_video(gambar_path, beat_info, output_video):
    try:
        img = Image.open(gambar_path).convert("RGB")
        img = img.resize((1080, 1920))
        img_array = np.array(img)
        beat_times = beat_info['beat_times']
        duration = beat_info['duration']
        if not beat_times:
            beat_times = np.linspace(0, duration, num=20).tolist()
        clips = []
        start = 0
        for i, t in enumerate(beat_times):
            end = t if t <= duration else duration
            dur = max(0.3, min(end - start, 2.0))
            if dur <= 0:
                continue
            anim = i % 5
            clip = ImageClip(img_array, duration=dur)
            if anim == 0:
                clip = clip.resize(lambda t: 1 + t*0.5)
            elif anim == 1:
                clip = clip.resize(lambda t: 1.5 - t*0.5)
            elif anim == 2:
                clip = clip.rotate(lambda t: np.sin(t*20)*3)
            elif anim == 3:
                clip = clip.resize(lambda t: 1 + np.sin(t*30)*0.05)
            else:
                clip = clip.resize(lambda t: 1 + t*0.3).set_position(lambda t: (np.sin(t*10)*50, 'center'))
            clips.append(clip)
            start = end
            if start >= duration:
                break
        if not clips:
            clips = [ImageClip(img_array, duration=duration)]
        final = concatenate_videoclips(clips, method="compose")
        if final.duration < duration:
            final = final.loop(duration=duration)
        elif final.duration > duration:
            final = final.subclip(0, duration)
        final.write_videofile(output_video, fps=24, codec='libx264', audio=False, verbose=False, logger=None)
        tulis_log(f"Video generated: {output_video}")
        return output_video
    except Exception as e:
        tulis_log(f"Error generate video: {e}")
        return None

# ================= 5. GABUNG VIDEO + AUDIO =================
def merge_video_audio(video_path, audio_path, output_final):
    try:
        video = VideoFileClip(video_path)
        audio = AudioFileClip(audio_path)
        if video.duration > audio.duration:
            video = video.subclip(0, audio.duration)
        elif video.duration < audio.duration:
            video = video.loop(duration=audio.duration)
        final = video.set_audio(audio)
        final.write_videofile(output_final, fps=24, codec='libx264', audio_codec='aac', verbose=False, logger=None)
        final.close()
        video.close()
        audio.close()
        tulis_log(f"Video final: {output_final}")
        return output_final
    except Exception as e:
        tulis_log(f"Gagal merge: {e}")
        return None

# ================= 6. UPLOAD KE FACEBOOK (PYPPETEER) =================
async def upload_to_facebook(video_path, caption="Hewan Joget Dangdut Viral! 🔥 #hewanjoget #dangdutviral #fyp"):
    tulis_log("Memulai upload ke Facebook...")
    browser = await launch(headless=False, args=['--no-sandbox', '--disable-setuid-sandbox'])
    page = await browser.newPage()
    if os.path.exists(SESSION_FILE):
        with open(SESSION_FILE, 'r') as f:
            cookies = json.load(f)
            await page.setCookie(*cookies)
    try:
        await page.goto('https://www.facebook.com/reels/your_reels', {'waitUntil': 'networkidle2'})
        if not os.path.exists(SESSION_FILE):
            tulis_log("⚠️ Login manual: Silakan login di browser yang muncul, lalu tekan ENTER.")
            input("Sudah login? Tekan ENTER...")
            cookies = await page.cookies()
            with open(SESSION_FILE, 'w') as f:
                json.dump(cookies, f)
            tulis_log("Session tersimpan.")
        create_selector = 'div[aria-label="Create a reel"], div[aria-label="Buat Reel"], div[data-testid="reels_create_button"]'
        try:
            await page.waitForSelector(create_selector, timeout=5000)
            await page.click(create_selector)
        except:
            await page.goto('https://www.facebook.com/reels/create/')
        await asyncio.sleep(3)
        file_input = await page.querySelector('input[type="file"]')
        if not file_input:
            tulis_log("Input file tidak ditemukan, silakan upload manual.")
            input("Upload video MANUAL di browser, lalu tekan ENTER...")
        else:
            await file_input.uploadFile(video_path)
            tulis_log("Video terupload, menunggu...")
            await asyncio.sleep(15)
        caption_selector = 'textarea[aria-label*="caption"], div[role="textbox"][contenteditable="true"]'
        try:
            await page.waitForSelector(caption_selector, timeout=10000)
            await page.type(caption_selector, caption)
        except:
            pass
        share_selector = 'div[aria-label="Share now"], div[aria-label="Bagikan"], div[aria-label="Publish"]'
        try:
            await page.waitForSelector(share_selector, timeout=5000)
            await page.click(share_selector)
            tulis_log("Tombol share diklik.")
        except:
            input("Klik SHARE secara MANUAL di browser, lalu ENTER...")
        await asyncio.sleep(5)
        tulis_log("Upload selesai!")
        await browser.close()
        return True
    except Exception as e:
        tulis_log(f"Error upload: {e}")
        await browser.close()
        return False

# ================= PROSES 1 VIDEO LENGKAP =================
async def proses_satu_video(gambar_paths):
    tulis_log("\n" + "="*50)
    tulis_log("Memulai proses satu video...")
    urls = scrape_trending_reels()
    if not urls:
        return False
    url = random.choice(urls)
    audio = download_audio_from_reels(url)
    if not audio:
        return False
    beat = get_beat_times(audio)
    if not beat:
        return False
    gambar = random.choice(gambar_paths)
    temp_vid = tempfile.NamedTemporaryFile(delete=False, suffix=".mp4").name
    vid = generate_sync_video(gambar, beat, temp_vid)
    if not vid:
        return False
    final_vid = tempfile.NamedTemporaryFile(delete=False, suffix=".mp4").name
    final = merge_video_audio(vid, audio, final_vid)
    if not final:
        return False
    success = await upload_to_facebook(final)
    for f in [audio, temp_vid, final]:
        try:
            os.unlink(f)
        except:
            pass
    return success

# ================= JADWAL 10 VIDEO PER HARI =================
async def run_jadwal():
    tulis_log(f"🤖 BOT AKTIF | Target {TARGET_VIDEO_PER_HARI} video/hari | Jeda {JEDA_DETIK//3600} jam {JEDA_DETIK%3600//60} menit")
    gambar_files = simpan_gambar_dari_base64()
    try:
        while True:
            success = await proses_satu_video(gambar_files)
            if success:
                tulis_log(f"✅ Berhasil. Tunggu {JEDA_DETIK} detik.")
            else:
                tulis_log(f"❌ Gagal. Tunggu {JEDA_DETIK} detik.")
            await asyncio.sleep(JEDA_DETIK)
    finally:
        for f in gambar_files:
            try:
                os.unlink(f)
            except:
                pass

# ================= MAIN =================
if __name__ == "__main__":
    print("🚀 BOT HEWAN JOGET DANGDUT VIRAL - VERSI LENGKAP")
    print("Pertama kali: login Facebook MANUAL di browser yang akan muncul.")
    print("Setelah login, bot akan berjalan otomatis.")
    asyncio.run(run_jadwal())
